set -euo pipefail

readonly SCRIPT_NAME="$(basename "$0")"
readonly LOG_FILE="/var/log/db_maintenance.log"

# Allowed maintenance commands (whitelist approach)
readonly ALLOWED_COMMANDS=(
    "ANALYZE TABLE"
    "OPTIMIZE TABLE"
    "CHECK TABLE"
    "REPAIR TABLE"
    "SHOW TABLE STATUS"
    "SHOW PROCESSLIST"
    "SHOW DATABASES"
    "SHOW TABLES"
    "SELECT COUNT"
    "FLUSH TABLES"
    "FLUSH PRIVILEGES"
    "FLUSH LOGS"
)

usage() {
    cat <<EOF
Usage: $SCRIPT_NAME [OPTIONS] "SQL_COMMAND"

Database Maintenance Toolkit - Execute maintenance SQL commands securely.

Options:
    -d, --database DATABASE   Target database name
    -h, --host HOST           Database host (default: localhost)
    -u, --user USER           Database user (default: root)
    -p, --port PORT           Database port (default: 3306)
    -c, --config FILE         MySQL config file for credentials
    -n, --dry-run             Show command without executing
    -v, --verbose             Enable verbose output
    --help                    Show this help message

Examples:
    $SCRIPT_NAME -d mydb "ANALYZE TABLE users"
    $SCRIPT_NAME -d mydb "OPTIMIZE TABLE orders"
    $SCRIPT_NAME -d mydb "CHECK TABLE products"
    $SCRIPT_NAME --config /root/.my.cnf -d mydb "SHOW TABLE STATUS"

IMPORTANT: Database credentials should be stored in a MySQL option file
           (e.g., ~/.my.cnf) rather than passed on the command line.
EOF
    exit 0
}

log_message() {
    local level="$1"
    local message="$2"
    local timestamp
    timestamp="$(date '+%Y-%m-%d %H:%M:%S')"
    echo "[$timestamp] [$level] $message" | tee -a "$LOG_FILE" >&2
}

validate_sql_command() {
    local command="$1"

    # Check for empty command
    if [[ -z "$command" ]]; then
        log_message "ERROR" "Empty SQL command provided"
        return 1
    fi

    # Block dangerous patterns - defense in depth
    local dangerous_patterns=(
        "DROP DATABASE"
        "DROP TABLE"
        "DROP USER"
        "TRUNCATE"
        "DELETE FROM"
        "UPDATE.*SET"
        "INSERT INTO"
        "CREATE USER"
        "GRANT ALL"
        "INTO OUTFILE"
        "INTO DUMPFILE"
        "LOAD_FILE"
        "LOAD DATA"
        "SYSTEM"
        "\\\\!"
    )

    local upper_command
    upper_command="$(echo "$command" | tr '[:lower:]' '[:upper:]')"

    for pattern in "${dangerous_patterns[@]}"; do
        if [[ "$upper_command" =~ $pattern ]]; then
            log_message "ERROR" "Blocked dangerous SQL pattern: $pattern"
            return 1
        fi
    done

    # Check against whitelist
    local allowed=false
    for allowed_cmd in "${ALLOWED_COMMANDS[@]}"; do
        if [[ "$upper_command" == ${allowed_cmd}* ]]; then
            allowed=true
            break
        fi
    done

    if [[ "$allowed" != true ]]; then
        log_message "ERROR" "Command not in allowed list: $command"
        log_message "INFO" "Allowed commands: ${ALLOWED_COMMANDS[*]}"
        return 1
    fi

    # Block shell metacharacters that could enable injection
    if [[ "$command" =~ [\;\|\&\$\`\\] ]]; then
        log_message "ERROR" "SQL command contains disallowed shell metacharacters"
        return 1
    fi

    return 0
}

validate_identifier() {
    local value="$1"
    local name="$2"

    # Only allow alphanumeric, underscore, hyphen, and dot
    if [[ ! "$value" =~ ^[a-zA-Z0-9._-]+$ ]]; then
        log_message "ERROR" "Invalid $name: contains disallowed characters"
        return 1
    fi
    return 0
}

execute_sql() {
    local sql_command="$1"
    local db_host="$2"
    local db_port="$3"
    local db_user="$4"
    local db_name="$5"
    local config_file="$6"
    local dry_run="$7"
    local verbose="$8"

    # Build mysql arguments as an array (safe from injection)
    local mysql_args=()

    # Use config file for credentials (secure approach)
    if [[ -n "$config_file" ]]; then
        if [[ ! -f "$config_file" ]]; then
            log_message "ERROR" "Config file not found: $config_file"
            return 1
        fi
        # Verify config file permissions
        local perms
        perms="$(stat -c '%a' "$config_file" 2>/dev/null || stat -f '%Lp' "$config_file" 2>/dev/null)"
        if [[ "$perms" != "600" && "$perms" != "400" ]]; then
            log_message "WARNING" "Config file $config_file has loose permissions ($perms). Should be 600 or 400."
        fi
        mysql_args+=("--defaults-extra-file=$config_file")
    fi

    mysql_args+=("--host=$db_host")
    mysql_args+=("--port=$db_port")
    mysql_args+=("--user=$db_user")

    if [[ -n "$db_name" ]]; then
        mysql_args+=("--database=$db_name")
    fi

    # Pass SQL command via -e flag (NOT through eval)
    mysql_args+=("--execute=$sql_command")

    # Additional safety options
    mysql_args+=("--batch")
    mysql_args+=("--connect-timeout=30")

    if [[ "$verbose" == true ]]; then
        log_message "INFO" "MySQL args (sanitized): host=$db_host port=$db_port user=$db_user database=$db_name"
        log_message "INFO" "SQL Command: $sql_command"
    fi

    if [[ "$dry_run" == true ]]; then
        log_message "INFO" "[DRY RUN] Would execute: mysql [credentials] --host=$db_host --port=$db_port --database=$db_name -e \"$sql_command\""
        return 0
    fi

    log_message "INFO" "Executing maintenance command: $sql_command"

    # Execute mysql directly â€” NO eval, NO shell expansion of user input
    local output
    local exit_code=0
    output="$(mysql "${mysql_args[@]}" 2>&1)" || exit_code=$?

    if [[ $exit_code -eq 0 ]]; then
        log_message "INFO" "Command executed successfully"
        if [[ -n "$output" ]]; then
            echo "$output"
        fi
    else
        log_message "ERROR" "Command failed with exit code $exit_code"
        log_message "ERROR" "Output: $output"
        return $exit_code
    fi
}

