main() {
    local db_host="localhost"
    local db_port="3306"
    local db_user="root"
    local db_name=""
    local config_file=""
    local dry_run=false
    local verbose=false
    local sql_command=""

    # Parse arguments
    while [[ $# -gt 0 ]]; do
        case "$1" in
            -d|--database)
                db_name="$2"
                shift 2
                ;;
            -h|--host)
                db_host="$2"
                shift 2
                ;;
            -u|--user)
                db_user="$2"
                shift 2
                ;;
            -p|--port)
                db_port="$2"
                shift 2
                ;;
            -c|--config)
                config_file="$2"
                shift 2
                ;;
            -n|--dry-run)
                dry_run=true
                shift
                ;;
            -v|--verbose)
                verbose=true
                shift
                ;;
            --help)
                usage
                ;;
            -*)
                log_message "ERROR" "Unknown option: $1"
                usage
                ;;
            *)
                sql_command="$1"
                shift
                ;;
        esac
    done

    # Validate required inputs
    if [[ -z "$sql_command" ]]; then
        log_message "ERROR" "No SQL command provided"
        usage
    fi

    # Validate all identifiers
    validate_identifier "$db_host" "hostname" || exit 1
    validate_identifier "$db_user" "username" || exit 1
    if [[ -n "$db_name" ]]; then
        validate_identifier "$db_name" "database name" || exit 1
    fi
    if [[ ! "$db_port" =~ ^[0-9]+$ ]]; then
        log_message "ERROR" "Invalid port number: $db_port"
        exit 1
    fi

    # Validate SQL command against whitelist
    validate_sql_command "$sql_command" || exit 1

    # Check if mysql client is available
    if ! command -v mysql &>/dev/null; then
        log_message "ERROR" "mysql client not found in PATH"
        exit 1
    fi

    # Check for config file if not specified, look for default
    if [[ -z "$config_file" && -f "$HOME/.my.cnf" ]]; then
        config_file="$HOME/.my.cnf"
        log_message "INFO" "Using default config file: $config_file"
    elif [[ -z "$config_file" ]]; then
        log_message "WARNING" "No MySQL config file specified. You may be prompted for a password."
        log_message "INFO" "Recommended: Create ~/.my.cnf with [client] section for credentials"
    fi

    # Execute
    execute_sql "$sql_command" "$db_host" "$db_port" "$db_user" "$db_name" "$config_file" "$dry_run" "$verbose"
}

main "$@"